xpath.script:
(function () {
  function jsonrpc(url, params) {
    return fetch(url, {
      method: "POST",
      headers: {"Content-Type": "application/json"},
      body: JSON.stringify({
        jsonrpc: "2.0",
        method: "call",
        params: params || {},
        id: Date.now()
      }),
      credentials: "same-origin",
    }).then(function (r) { return r.json(); })
      .then(function (r) { return r.result; });
  }

  function getMode() {
    var el = document.querySelector("input[name='oms_payment_mode']:checked");
    return el ? (el.value || "").toLowerCase() : "full";
  }

  function ensureHidden() {
    var form = document.getElementById("o_payment_form");
    if (!form) return null;
    var hidden = form.querySelector("input[name='oms_payment_mode_hidden']");
    if (!hidden) {
      hidden = document.createElement("input");
      hidden.type = "hidden";
      hidden.name = "oms_payment_mode";
      hidden.value = "full";
      hidden.setAttribute("name", "oms_payment_mode");
      hidden.setAttribute("data-oms", "1");
      hidden.id = "oms_payment_mode_hidden";
      form.appendChild(hidden);
    }
    return hidden;
  }

  function ensureCommentHidden() {
    var form = document.getElementById("o_payment_form");
    if (!form) return null;
    var hidden = form.querySelector("input[name='Comments']#oms_comments_hidden");
    if (!hidden) {
      hidden = document.createElement("input");
      hidden.type = "hidden";
      hidden.name = "Comments"; // map to sale_custom.order.Comments
      hidden.value = "";
      hidden.setAttribute("data-oms", "1");
      hidden.id = "oms_comments_hidden";
      form.appendChild(hidden);
    }
    return hidden;
  }

  function getComment() {
    var el = document.getElementById("oms_comments_input");
    return el ? (el.value || "").toString() : "";
  }

  function syncComment() {
    var comment = getComment();
    if (comment && comment.length > 240) comment = comment.slice(0, 240);

    var hidden = ensureCommentHidden();
    if (hidden) hidden.value = comment;

    // store to session as backend fallback
    return jsonrpc("/payment/sepay/set_comment", {comment: comment}).catch(function () {});
  }

  function toggleBoxes(mode) {
    var uncBox = document.getElementById("o_ws_unc_box");
    var creditBox = document.getElementById("o_ws_credit_box");
    if (uncBox) uncBox.classList.toggle("d-none", mode !== "unc");
    if (creditBox) creditBox.classList.toggle("d-none", mode !== "credit");
  }

  function syncMode() {
    var mode = getMode();
    toggleBoxes(mode);

    var hidden = ensureHidden();
    if (hidden) hidden.value = mode;

    // lưu session để backend fallback được (không phụ thuộc hidden)
    return jsonrpc("/payment/sepay/set_mode", {mode: mode}).then(function (result) {
      if (result && result.pricelist_changed && !window.__omsStrategicPriceReloading) {
        window.__omsStrategicPriceReloading = true;
        window.location.reload();
      }
      return result;
    }).catch(function () {});
  }

  document.addEventListener("change", function (e) {
    if (e.target && e.target.name === "oms_payment_mode") {
      syncMode();
    }
  });

  document.addEventListener("input", function (e) {
    if (e.target && e.target.id === "oms_comments_input") {
      syncComment();
    }
  });

  document.addEventListener("submit", function (e) {
    var form = e.target;
    if (!form || form.id !== "o_payment_form") return;

    var mode = getMode();
    if (mode === "credit") {
      var cb = document.getElementById("oms_credit_confirm");
      if (!cb || !cb.checked) {
        e.preventDefault();
        e.stopPropagation();
        alert("Vui lòng xác nhận điều khoản công nợ trước khi tiếp tục.");
        return false;
      }
    }
    // Sync both before submitting payment
    syncComment();
    syncMode();
    return true;
  }, true);

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function () {
      ensureHidden();
      ensureCommentHidden();
      syncComment();
      syncMode();
    });
  } else {
    ensureHidden();
    ensureCommentHidden();
    syncComment();
    syncMode();
  }
})();
